/**
 * AUTO-GENERATED. Tree catalog.
 */

export interface TreeImage {
  url: string; thumb: string | null;
  width: number; height: number;
  thumbWidth: number | null; thumbHeight: number | null;
  artist: string | null; license: string | null;
  sourceUrl: string | null;
}

/** Labelled detail photo — used for the 4-up gallery on tree detail pages. */
export interface TreeDetailImage extends TreeImage {
  /** What part of the tree this shows */
  kind: "whole" | "bark" | "needles" | "cone" | "leaf" | "flower" | "habitat";
  /** Short caption */
  caption?: string;
}

/** Field-key identification details — designed for "what pine is this?" use. */
export interface TreeIdentification {
  /** Bundle count + length + color + persistence for conifers; leaf shape/size for hardwoods */
  needles?: {
    perBundle?: number;
    /** "10–25 cm" */
    lengthCm?: string;
    color?: string;
    persistenceYears?: string;
    notes?: string;
  };
  bark?: {
    /** "Reddish-brown plates, smelling of vanilla / butterscotch" */
    description: string;
    /** "Plates / Furrowed / Smooth / Scaly" */
    pattern?: string;
  };
  cones?: {
    /** "8–15 cm long, conic-ovate, persistent" */
    description: string;
    sizeCm?: string;
    /** Does it stay on the tree, drop intact, or shatter on the ground */
    behavior?: string;
  };
  crown?: string;
  /** Mature height range, e.g. "30–60 m" */
  matureHeightM?: string;
  /** Mature trunk diameter range, e.g. "60–250 cm" */
  matureDbhCm?: string;
  /** Native range summary */
  range?: string;
  /** Elevation range in PNW/Sierra context */
  elevationM?: { min: number; max: number };
  /** The single best one-line "you'll know it because…" tell */
  keyTell?: string;
}

/** Note for a confusable lookalike — links one tree to another with what to look for. */
export interface ConfusableNote {
  /** Other tree's id in this catalog */
  treeId: string;
  /** Why they get confused and how to tell them apart */
  distinguishingFeature: string;
}

export interface TreeProfile {
  id: string; common: string; scientific: string;
  description: string | null; summary: string | null;
  pageUrl: string | null;
  /** Legacy single-photo field; new entries should also fill `images`. */
  image: TreeImage | null;
  /** Multi-photo gallery (whole tree, bark, needles, cone). */
  images?: TreeDetailImage[];
  /** Structured field-key identification — needles, bark, cones, etc. */
  identification?: TreeIdentification;
  /** Other trees this one gets confused with, with telling differences. */
  confusableWith?: ConfusableNote[];
  /** When the data was last verified (YYYY-MM-DD). */
  lastVerified?: string;
  speciesRefs: string[];
}

